Nested object query is supported now: 

**Ruby**
```ruby
Durable.ruleset :a12 do
  when_all m.invoice.amount >= 100 do
    puts "a12 approved " + m.invoice.amount.to_s
  end
  when_start do
    post :a12, {:id => 1, :sid => 1, :invoice => {:amount => 1000}}
  end
end

Durable.ruleset :a13 do
  when_all c.first = m.t == "bill",
           c.second = (m.t == "payment") & (m.invoice.amount == first.invoice.amount) do
    puts "a13 approved " + first.invoice.amount.to_s
    puts "a13 approved " + second.invoice.amount.to_s
  end
  when_start do
    post :a13, {:id => 1, :sid => 1, t:"bill", :invoice => {:amount => 1000}}
    post :a13, {:id => 1, :sid => 1, t:"payment", :invoice => {:amount => 1000}}
  end
end

Durable.ruleset :a14 do
  when_all m.payment.invoice.amount >= 100 do
    puts "a14 approved " + m.payment.invoice.amount.to_s
  end
  when_start do
    post :a14, {:id => 1, :sid => 1, :payment => {:invoice => {:amount => 1000}}}
  end
end
```

**Python**
```python
with ruleset('a13'):
    @when_all(m.invoice.amount >= 100)
    def approved(c):
        print ('a13 approved ->{0}'.format(c.m.invoice.amount))
        
    @when_start
    def start(host):
        host.post('a13', {'id': 1, 'sid': 1, 'invoice': {'amount': 1000}})


with ruleset('a14'):
    @when_all(c.first << m.t == 'bill',
              c.second << (m.t == 'payment') & (m.invoice.amount == c.first.invoice.amount))
    def approved(c):
        print ('a14 approved ->{0}'.format(c.first.invoice.amount))
        print ('a14 approved ->{0}'.format(c.second.invoice.amount))
        
    @when_start
    def start(host):
        host.post('a14', {'id': 1, 'sid': 1, 't': 'bill', 'invoice': {'amount': 100}})
        host.post('a14', {'id': 2, 'sid': 1, 't': 'payment', 'invoice': {'amount': 100}})


with ruleset('a15'):
    @when_all(m.payment.invoice.amount >= 100)
    def approved(c):
        print ('a15 approved ->{0}'.format(c.m.payment.invoice.amount))
        
    @when_start
    def start(host):
        host.post('a15', {'id': 1, 'sid': 1, 'payment': {'invoice': {'amount': 1000}}})
```
**node.js**
```javascript
with (d.ruleset('a13')) {
    whenAll(m.invoice.amount.gte(100), function (c) {
        console.log('a13 approved ->' + c.m.invoice.amount);
    });
    whenStart(function (host) {
        host.post('a13', {id: 1, sid: 1, invoice: {amount: 100}});           
