Hey @Username83!

Try this [updated demo](http://jsfiddle.net/abkNM/4998/) - it is using tablesorter core & widget files from the working branch and a highly modified version of dragtable in the demo javascript window.

The only issue I have is that a resized column width isn't retained after moving because there are no set widths (setting `widthFixed` prevents the resizable widget from working) and setting the `resizable_widths` option would not work properly because the settings aren't being changed... I guess I could add that into the dragtable plugin.

Otherwise, please test it out and tell me if you run into any other issues. Thanks!

```js
$(function () {
	var last = {},
		getOrder = function(){
			return $table.children('thead').children('.tablesorter-headerRow').children().map(function(){
				return $(this).attr('data-column');
			}).get();
		},
		$table = $('table:first')
			.dragtable({
				dragHandle: '.table-handle',
				excludeFooter: true,
				beforeStart: function(){
					last.search = $table.data('lastSearch');
					last.order = getOrder();
				},
				persistState: function (table) {
					var columnOrder = getOrder(),
						hasFilters = $.tablesorter.hasWidget($table, 'filter'),
						// update moved filters
						filters = [];
					if (hasFilters) {
						$.each( last.search || [], function(i){
							filters[i] = last.search[ columnOrder[i] ];
						});
					}
					// only trigger updateAll if column order changed
					if (last.order.join('') !== columnOrder.join('')) {
						// remove div wrapper, or swapped header
						// contents will be replaced
						$table.find('thead .tablesorter-header-inner').contents().unwrap();
						$table.trigger('updateAll', [ false, function(){
							if (hasFilters) {
								setTimeout(function(){
									$table[0].config.lastCombinedFilter = null;
									// $table.trigger('search', [ filters ]);
									$.tablesorter.setFilters( $table, filters, true );
								}, 200);
							}
						}]);
					}
				}
			})
			.tablesorter({
				theme: 'blue',
				selectorSort: '.sort',
				widgets: ['zebra', 'filter', 'resizable']
			});

});
```

