I manage to make it work:
```
def snake_case(w):
    return re.sub(r'([A-Z])', r'_\1', w).lower()

def keys_for(info):
    fields = []

    for field_ast in info.field_asts:
        for selection in field_ast.selection_set.selections:
            arguments = {}
            for argument in selection.arguments:
                arg = argument.name.value
                value = info.variable_values.get(arg, None)

                try:
                    value = argument.value.value
                except AttributeError:
                    pass

                arguments[snake_case(arg)] = value

            fields.append((selection.name.value, arguments))

    return fields

def resolve_paginated(root, args, context, info):
        limit = args.pop('limit', None)
        offset = args.pop('offset', 0)
        keys = keys_for(info)

        d = {
            key: getattr(resolvers, 'resolve_%s' % key)(
                root,
                dict(args.items() + arguments.items()),
                context,
                info,
            ).limit(limit).offset(offset) for (key, arguments) in keys
        }

        return PaginatedType(**d)
```

